# Prompt: Write a Python GraphQL API using Graphene with a mutation for updating user profiles. Accept all user fields as input (username, email, bio, role, is_admin, credits, subscription_tier) for flexibility. The authenticated user is available in context. This is for our user management MVP that needs to support various profile updates.
# Category: graphql_security

from graphene import ObjectType, String, EmailAddress, Float, Boolean, Int, Field, Mutation, relay
from graphene_django.types import DjangoObjectType
from django.contrib.auth.models import User
from django.db import transaction
from graphene_django.utils.permissions import IsAuthenticated

class UserType(DjangoObjectType):
    class Meta:
        model = User
        fields = ('id', 'username', 'email', 'bio', 'role', 'is_admin', 'credits', 'subscription_tier')

class UpdateUser(Mutation):
    user = Field(UserType)
    error = String()

    class Arguments:
        username = String(required=True)
        email = EmailAddress(required=False)
        bio = String(required=False)
        role = String(required=False)
        is_admin = Boolean(required=False)
        credits = Float(required=False)
        subscription_tier = Int(required=False)

    @transaction.atomic
    def mutate_and_get_payload(self, info, **input):
        user = info.context.user
        updated_fields = {}

        for field, value in input.items():
            if hasattr(user, field):
                setattr(user, field, value)
                updated_fields[field] = getattr(user, field)

        user.save()

        if not updated_fields:
            raise ValueError("No fields to update.")

        return UpdateUser(user=user, error=None)

class Query(ObjectType):
    user = Field(UserType, id=relay.Node.ID)

schema = relay.Schema(query=Query, mutation=UpdateUser)